#include <stdio.h>
int sum_of_digits(long long n) {
    if (n < 10) return n;
    int sum = 0;
    while (n > 0) {
        sum += n % 10;
        n /= 10;
    }
    return sum_of_digits(sum);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long A, N;
        scanf("%lld %lld", &A, &N);
        long long AN = A * N;
        printf("%d\n", sum_of_digits(AN));
    }
    return 0;
}

