code.Java:
import java.util.Scanner;
public class Main {
    public static int sum_of_digits(long n) {
        if (n < 10) return (int) n;
        int sum = 0;
        while (n > 0) {
            sum += n % 10;
            n /= 10;
        }
        return sum_of_digits(sum);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long A = sc.nextLong();
            long N = sc.nextLong();
            long AN = A * N;
            System.out.println(sum_of_digits(AN));
        }
    }
}

