const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function sum_of_digits(n) {
    if (n < 10) return n;
    let sum = 0;
    while (n > 0) {
        sum += n % 10;
        n = Math.floor(n / 10);
    }
    return sum_of_digits(sum);
}
let T = parseInt(lines[idx++]);
while (T-- > 0) {
    let [A, N] = lines[idx++].trim().split(' ').map(x => BigInt(x));
    let AN = A * N;
    console.log(sum_of_digits(Number(AN)));
}

